    public String generateBackupCode() {
        StringBuilder code = new StringBuilder();
        for (int i = 0; i < 16; i++) {
            code.append(String.format("%02d", random.nextInt(100)));
            if (i % 4 == 3 && i != 15) code.append("-");
        }
        return code.toString();
    }

    public List<BackupCode> generateBackupCodes(User user) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        if (codes != null && !codes.isEmpty()) {
            return codes;
        }

        codes = new java.util.ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String code = generateBackupCode();
            BackupCode backupCode = new BackupCode(user, code);
            codes.add(backupCode);
        }
        return backupCodeRepository.saveAll(codes);
    }

    public void enableMfa(Long userId) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));
        user.setMfaEnabled(true);
        user.setMfaEnabledAt(LocalDateTime.now());
        userRepository.save(user);
    }

    public boolean validateBackupCode(String code) {
        Optional<BackupCode> backupCodeOpt = backupCodeRepository.findByCodeAndUsedFalse(code);
        if (backupCodeOpt.isPresent()) {
            BackupCode backupCode = backupCodeOpt.get();
            backupCode.setUsed(true);
            backupCode.setUsedAt(LocalDateTime.now());
            backupCodeRepository.save(backupCode);
            return true;
        }
        return false;
    }

