@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<?> enableMfa(@RequestParam Long userId) {
        try {
            mfaService.enableMfa(userId);
            return ResponseEntity.ok().build();
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Error enabling MFA: " + e.getMessage());
        }
    }

    @GetMapping("/backup-codes")
    public ResponseEntity<?> generateBackupCodes(@RequestParam Long userId) {
        try {
            User user = new User();
            user.setId(userId);
            List<BackupCode> codes = mfaService.generateBackupCodes(user);
            return ResponseEntity.ok(codes);
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Error generating backup codes: " + e.getMessage());
        }
    }

    @PostMapping("/verify-backup")
    public ResponseEntity<?> verifyBackupCode(@RequestParam String username, 
                                             @RequestParam String backupCode) {
        try {
            boolean valid = mfaService.authenticateWithBackupCode(username, backupCode);
            if (valid) {
                return ResponseEntity.ok().build();
            } else {
                return ResponseEntity.badRequest().body("Invalid backup code");
            }
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Error verifying backup code: " + e.getMessage());
        }
    }

    @PostMapping("/verify-totp")
    public ResponseEntity<?> verifyTotp(@RequestParam String username, 
                                       @RequestParam String token) {
        try {
            boolean valid = mfaService.verifyMfaToken(username, token);
            if (valid) {
                return ResponseEntity.ok().build();
            } else {
                return ResponseEntity.badRequest().body("Invalid TOTP token");
            }
        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Error verifying TOTP: " + e.getMessage());
        }
    }
}